60	    // Este construtor lê o modelo de um arquivo utilizando a biblioteca tinyobjloader.
61	    // Veja: https://github.com/syoyo/tinyobjloader
62	    ObjModel(const char* filename, const char* basepath = NULL, bool triangulate = true)
63	    {
64	        printf("Carregando objetos do arquivo \"%s\"...\n", filename);
65	
66	        // Se basepath == NULL, então setamos basepath como o dirname do
67	        // filename, para que os arquivos MTL sejam corretamente carregados caso
68	        // estejam no mesmo diretório dos arquivos OBJ.
69	        std::string fullpath(filename);
70	        std::string dirname;
71	        if (basepath == NULL)
72	        {
73	            auto i = fullpath.find_last_of("/");
74	            if (i != std::string::npos)
75	            {
76	                dirname = fullpath.substr(0, i+1);
77	                basepath = dirname.c_str();
78	            }
79	        }
80	
81	        std::string warn;
82	        std::string err;
83	        bool ret = tinyobj::LoadObj(&attrib, &shapes, &materials, &warn, &err, filename, basepath, triangulate);
84	
85	        if (!err.empty())
86	            fprintf(stderr, "\n%s\n", err.c_str());
87	
88	        if (!ret)
89	            throw std::runtime_error("Erro ao carregar modelo.");
90	
91	        for (size_t shape = 0; shape < shapes.size(); ++shape)
92	        {
93	            if (shapes[shape].name.empty())
94	            {
95	                fprintf(stderr,
96	                        "*********************************************\n"
97	                        "Erro: Objeto sem nome dentro do arquivo '%s'.\n"
