236	int main(int argc, char* argv[])
237	{
238	    // Inicializamos a biblioteca GLFW, utilizada para criar uma janela do
239	    // sistema operacional, onde poderemos renderizar com OpenGL.
240	    int success = glfwInit();
241	    if (!success)
242	    {
243	        fprintf(stderr, "ERROR: glfwInit() failed.\n");
244	        std::exit(EXIT_FAILURE);
245	    }
246	
247	    // Definimos o callback para impressão de erros da GLFW no terminal
248	    glfwSetErrorCallback(ErrorCallback);
249	
250	    // Pedimos para utilizar OpenGL versão 3.3 (ou superior)
251	    glfwWindowHint(GLFW_CONTEXT_VERSION_MAJOR, 3);
252	    glfwWindowHint(GLFW_CONTEXT_VERSION_MINOR, 3);
253	
254	    #ifdef __APPLE__
255	    glfwWindowHint(GLFW_OPENGL_FORWARD_COMPAT, GL_TRUE);
256	    #endif
257	
258	    // Pedimos para utilizar o perfil "core", isto é, utilizaremos somente as
259	    // funções modernas de OpenGL.
260	    glfwWindowHint(GLFW_OPENGL_PROFILE, GLFW_OPENGL_CORE_PROFILE);
261	
262	    // Criamos uma janela do sistema operacional, com 800 colunas e 600 linhas
263	    // de pixels, e com título "INF01047 ...".
264	    GLFWwindow* window;
265	    window = glfwCreateWindow(800, 600, "INF01047 - Seu Cartao - Seu Nome", NULL, NULL);
266	    if (!window)
267	    {
268	        glfwTerminate();
269	        fprintf(stderr, "ERROR: glfwCreateWindow() failed.\n");
270	        std::exit(EXIT_FAILURE);
271	    }
272	
273	    // Definimos a função de callback que será chamada sempre que o usuário
274	    // pressionar alguma tecla do teclado ...
275	    glfwSetKeyCallback(window, KeyCallback);
276	    // ... ou clicar os botões do mouse ...
277	    glfwSetMouseButtonCallback(window, MouseButtonCallback);
278	    // ... ou movimentar o cursor do mouse em cima da janela ...
279	    glfwSetCursorPosCallback(window, CursorPosCallback);
280	    // ... ou rolar a "rodinha" do mouse.
281	    glfwSetScrollCallback(window, ScrollCallback);
282	
283	    // Indicamos que as chamadas OpenGL deverão renderizar nesta janela
284	    glfwMakeContextCurrent(window);
285	
286	    // Carregamento de todas funções definidas por OpenGL 3.3, utilizando a
287	    // biblioteca GLAD.
288	    gladLoadGLLoader((GLADloadproc) glfwGetProcAddress);
289	
290	    // Definimos a função de callback que será chamada sempre que a janela for
291	    // redimensionada, por consequência alterando o tamanho do "framebuffer"
292	    // (região de memória onde são armazenados os pixels da imagem).
293	    glfwSetFramebufferSizeCallback(window, FramebufferSizeCallback);
294	    FramebufferSizeCallback(window, 800, 600); // Forçamos a chamada do callback acima, para definir g_ScreenRatio.
295	
296	    // Imprimimos no terminal informações sobre a GPU do sistema
297	    const GLubyte *vendor      = glGetString(GL_VENDOR);
298	    const GLubyte *renderer    = glGetString(GL_RENDERER);
299	    const GLubyte *glversion   = glGetString(GL_VERSION);
